<?php
namespace Tests\Feature\Hr;
use App\Models\HrLicense; use App\Models\LegalEntity; use App\Models\User; use App\Modules\Hr\Core\Services\TenantContext; use Illuminate\Support\Facades\DB; use Tests\TestCase;
class PayrollPagesTest extends TestCase { use RefreshHrDatabase; public function test_payroll_prep_pages_render():void{(new \Database\Seeders\Hr\HrPermissionSeeder)->run();$role=DB::table('roles')->where('slug','hr_admin')->value('id');$user=User::factory()->create(['role_id'=>$role]);$this->actingAs($user);$tenant=LegalEntity::create(['user_id'=>$user->id,'name'=>'Test','tax_number'=>'1212121212','is_active'=>true]);app(TenantContext::class)->set($tenant);HrLicense::create(['legal_entity_id'=>$tenant->id,'module_key'=>'bordro','is_active'=>true]);$this->get(route('hr.payroll'))->assertOk()->assertSee('Bordro Çalışma Alanı');$this->get(route('hr.payroll.calculator'))->assertOk()->assertSee('Brüt–Net Hesaplama Aracı');$this->get(route('hr.settings.payroll-rules'))->assertOk()->assertSee('Bordro Kural Sürümleri');$this->get(route('hr.settings.payroll-profiles'))->assertOk()->assertSee('Çalışan Bordro Profilleri');} }
